const fixDriveLink = (idOrUrl: string) => {
    if (!idOrUrl) return "https://images.unsplash.com/photo-1610348725531-843dff563e2c?q=80&w=500&auto=format&fit=crop";
    
    if (idOrUrl.startsWith('http')) return idOrUrl;

    let cleanId = idOrUrl;
    if (idOrUrl.includes('id=')) {
        const parts = idOrUrl.split('id=');
        cleanId = parts[parts.length - 1];
    } else if (idOrUrl.includes('/d/')) {
        const parts = idOrUrl.split('/d/');
        cleanId = parts[1].split('/')[0];
    }

    cleanId = cleanId.split('/view')[0].split('?')[0].split('&')[0];
    
    return `https://lh3.googleusercontent.com/d/${cleanId}`;
};

const mapUnitArToEn = (unitAr: string): string => {
    if (unitAr.includes('كيلو')) return 'kg';
    if (unitAr.includes('حبة')) return 'pc';
    if (unitAr.includes('عبوة')) return 'PK';
    if (unitAr.includes('كرتون')) return 'Ctn';
    if (unitAr.includes('طبق')) return 'Box';
    if (unitAr.includes('سلة')) return 'Basket';
    return 'unit';
};

const mapCategory = (catAr: string, nameAr: string): CategoryKey => {
  const name = nameAr.toLowerCase();
  const cat = catAr.toLowerCase();

  // Priority 0: Handle explicitly imported if requested by origin or name
  if (name.includes('مستورد') || cat.includes('مستورد')) return 'imported';

  // Priority 1: Handle the mixed "Qassim, Dates & Others" category specifically
  if (cat.includes('القصيم') || cat.includes('تمور') || cat.includes('منوعة')) {
      // Check for Dates first within this category
      if (name.includes('تمر') || name.includes('سكري') || name.includes('مجدول') || name.includes('صقعي') || 
          name.includes('مبروم') || name.includes('صفاوي') || name.includes('عنبر') || name.includes('عجوة') || 
          name.includes('رطب') || name.includes('خلاص')) {
          return 'dates';
      }
      // Check for Packages/Baskets
      if (name.includes('سلة') || name.includes('صندوق') || name.includes('بيض') || name.includes('عبوة') || name.includes('مغلف')) {
          return 'packages';
      }
      // Check for Flowers
      if (name.includes('زهور') || name.includes('ورد')) return 'flowers';
      // Check for Fruits that might be here
      if (name.includes('توت') || name.includes('جوز الهند') || name.includes('قصب سكر') || name.includes('أناناس')) return 'fruits';
      // Check for Mushrooms
      if (name.includes('فطر')) return 'seasonal';
      
      // Default for this mixed category is Qassim
      return 'qassim';
  }

  // Priority 2: Standard Category Mapping
  if (cat.includes('تمور')) return 'dates';
  if (cat.includes('الورقيات') || cat.includes('أعشاب')) return 'herbs';
  if (cat.includes('الفواكه')) return 'fruits';
  if (cat.includes('المستوردة') || cat.includes('مستورد')) return 'imported';
  if (cat.includes('موسمية') || cat.includes('خاصة')) return 'seasonal';
  if (cat.includes('الأساسية والمحلية')) return 'vegetables';
  if (cat.includes('مكسرات')) return 'nuts';
  if (cat.includes('زهور')) return 'flowers';

  // Fallback
  return 'vegetables';
};

